// ============================================
// HLJ DEV — Lead Score Engine v1.0
// ============================================
// Pontuação baseada na qualidade do lead vindo
// do LeadChat da hljdev.com.br
// ============================================

const lead = $input.first().json.body;

let score = 0;
const flags = [];

// --- 1. Tem WhatsApp? (+20pts) ---
if (lead.whatsapp && lead.whatsapp.length >= 10) {
  score += 20;
  flags.push('✅ WhatsApp informado');
} else {
  flags.push('⚠️ Sem WhatsApp');
}

// --- 2. Interesse de Alto Valor (+30pts) ---
const interessesQuentes = [
  'Sistema Web/SaaS Exclusivo',
  'Agente de I.A (Venda/Suporte)'
];
const interessesMedio = [
  'Mentoria Avançada em n8n'
];
if (interessesQuentes.some(i => lead.interesse?.includes(i))) {
  score += 30;
  flags.push('🔥 Interesse Premium (SaaS/Agente IA)');
} else if (interessesMedio.some(i => lead.interesse?.includes(i))) {
  score += 15;
  flags.push('🌡️ Interesse Médio (Mentoria)');
} else {
  score += 5;
  flags.push('❄️ Interesse padrão (Prompts/Outro)');
}

// --- 3. Mensagem com substância (+30pts) ---
const mensagem = lead.mensagem || '';
if (mensagem.length > 200) {
  score += 30;
  flags.push('🔥 Mensagem detalhada (>200 chars)');
} else if (mensagem.length > 80) {
  score += 15;
  flags.push('🌡️ Mensagem razoável (80-200 chars)');
} else {
  score += 5;
  flags.push('❄️ Mensagem curta');
}

// --- 4. Email corporativo (+20pts) ---
const emailPessoal = ['gmail.com', 'hotmail.com', 'outlook.com', 'yahoo.com.br', 'yahoo.com'];
const dominioEmail = lead.email?.split('@')[1]?.toLowerCase() ?? '';
if (!emailPessoal.includes(dominioEmail) && dominioEmail.includes('.')) {
  score += 20;
  flags.push('🏢 Email corporativo detectado: ' + dominioEmail);
} else {
  flags.push('📧 Email pessoal: ' + dominioEmail);
}

// --- Classificação Final ---
let temperatura = '❄️ Frio';
if (score >= 70) temperatura = '🔥 Muito Quente';
else if (score >= 45) temperatura = '🌡️ Morno';
else if (score >= 25) temperatura = '🌡️ Frio-Morno';

return [
  {
    json: {
      ...lead,
      lead_score: score,
      lead_temperatura: temperatura,
      lead_flags: flags,
      status: 'novo',
      origem: lead.origem || 'site-hljdev',
      created_at: new Date().toISOString()
    }
  }
];

// Monta mensagem de alerta personalizada para o WhatsApp do Henrique
const lead = $('HLJ Score Engine').first().json;

const emoji = lead.lead_score >= 70 ? '🔥' : lead.lead_score >= 45 ? '🌡️' : '❄️';
const flagsText = lead.lead_flags.map(f => `  • ${f}`).join('\n');
const waLink = lead.whatsapp ? `https://wa.me/55${lead.whatsapp.replace(/\D/g,'')}?text=Oi%20${encodeURIComponent(lead.nome.split(' ')[0])}%2C%20vi%20sua%20mensagem%20no%20meu%20site!` : 'Sem WhatsApp';

const mensagem = `${emoji} *NOVO LEAD — HLJ DEV*
━━━━━━━━━━━━━━━━━━━
👤 *${lead.nome}*
📧 ${lead.email}
📱 ${lead.whatsapp || '—'}
🎯 *Interesse:* ${lead.interesse}

💬 *Mensagem:*
_${lead.mensagem}_

🧠 *Lead Score:* ${lead.lead_score}/100 — ${lead.lead_temperatura}
${flagsText}
━━━━━━━━━━━━━━━━━━━
📲 *Responder:* ${waLink}`;

return [{ json: { mensagem } }];
